import os
import sys
import shutil
import subprocess
import tempfile
import zipfile
from pathlib import Path

ROOT = Path(__file__).resolve().parent


def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def run(cmd, cwd=None, env=None):
    eprint("+", " ".join(cmd))
    subprocess.check_call(cmd, cwd=str(cwd) if cwd else None, env=env)


def python_exe():
    return sys.executable


def ensure_venv(venv_dir: Path):
    if os.name == "nt":
        vpy = venv_dir / "Scripts" / "python.exe"
        vpip = venv_dir / "Scripts" / "pip.exe"
    else:
        vpy = venv_dir / "bin" / "python"
        vpip = venv_dir / "bin" / "pip"
    if not vpy.exists():
        run([python_exe(), "-m", "venv", str(venv_dir)])
    run([str(vpy), "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel"])
    return vpy, vpip


def install_requirements(vpy: Path, requirements: Path):
    if not requirements.exists():
        eprint(f"requirements.txt not found at: {requirements}")
        sys.exit(2)
    run([str(vpy), "-m", "pip", "install", "-r", str(requirements)])


def run_tests(vpy: Path):
    # Prefer pytest if present; otherwise fall back to unittest discovery
    env = os.environ.copy()
    try:
        run([str(vpy), "-m", "pytest", "-q"], cwd=ROOT, env=env)
        return
    except subprocess.CalledProcessError:
        # If pytest isn't installed, try unittest; if pytest exists but tests failed, re-raise
        try:
            run([str(vpy), "-c", "import pytest; raise SystemExit(0)"])
            raise
        except subprocess.CalledProcessError:
            raise
        except Exception:
            run([str(vpy), "-m", "unittest", "discover", "-q"], cwd=ROOT, env=env)


def should_exclude(path: Path):
    parts = set(path.parts)
    if "__pycache__" in parts:
        return True
    if any(p.endswith(".pyc") or p.endswith(".pyo") for p in path.parts):
        return True
    for ex in (".git", ".hg", ".svn", ".idea", ".vscode", "venv", ".venv", "dist", "build", ".mypy_cache", ".pytest_cache", ".tox", ".ruff_cache"):
        if ex in parts:
            return True
    return False


def package_zip(output_path: Path, include_dirs=None, include_files=None):
    output_path.parent.mkdir(parents=True, exist_ok=True)
    if output_path.exists():
        output_path.unlink()

    include_dirs = include_dirs or []
    include_files = include_files or ["requirements.txt"]

    with zipfile.ZipFile(str(output_path), "w", compression=zipfile.ZIP_DEFLATED) as z:
        # Add explicit files
        for f in include_files:
            fp = ROOT / f
            if fp.exists() and fp.is_file():
                z.write(str(fp), arcname=str(fp.relative_to(ROOT)))

        # Add directories (recursive)
        for d in include_dirs:
            dp = ROOT / d
            if not dp.exists() or not dp.is_dir():
                continue
            for p in dp.rglob("*"):
                if p.is_dir():
                    continue
                rel = p.relative_to(ROOT)
                if should_exclude(rel):
                    continue
                z.write(str(p), arcname=str(rel))

        # Fallback: if no include_dirs provided, package typical app layout
        if not include_dirs:
            candidates = []
            for name in ("app", "src"):
                if (ROOT / name).is_dir():
                    candidates.append(name)
            if not candidates:
                # package all .py and common config files at repo root
                for p in ROOT.rglob("*"):
                    if p.is_dir():
                        continue
                    rel = p.relative_to(ROOT)
                    if should_exclude(rel):
                        continue
                    if rel.parts and rel.parts[0] not in {".", ""} and len(rel.parts) > 0:
                        pass
                    suffix = p.suffix.lower()
                    if suffix in {".py", ".toml", ".yaml", ".yml", ".json", ".ini", ".cfg", ".txt"} or p.name in {"Dockerfile", "Procfile"}:
                        z.write(str(p), arcname=str(rel))
            else:
                for name in candidates:
                    for p in (ROOT / name).rglob("*"):
                        if p.is_dir():
                            continue
                        rel = p.relative_to(ROOT)
                        if should_exclude(rel):
                            continue
                        z.write(str(p), arcname=str(rel))


def main():
    venv_dir = ROOT / ".ci_venv"
    requirements = ROOT / "requirements.txt"
    dist_dir = ROOT / "dist"
    artifact = dist_dir / "deployment_package.zip"

    include_dirs_env = os.environ.get("PACKAGE_INCLUDE_DIRS", "").strip()
    include_files_env = os.environ.get("PACKAGE_INCLUDE_FILES", "").strip()
    include_dirs = [s.strip() for s in include_dirs_env.split(",") if s.strip()] if include_dirs_env else []
    include_files = [s.strip() for s in include_files_env.split(",") if s.strip()] if include_files_env else ["requirements.txt"]

    vpy, _ = ensure_venv(venv_dir)
    install_requirements(vpy, requirements)
    run_tests(vpy)
    package_zip(artifact, include_dirs=include_dirs, include_files=include_files)

    print(str(artifact))


if __name__ == "__main__":
    try:
        main()
    except subprocess.CalledProcessError as e:
        eprint(f"Command failed with exit code {e.returncode}")
        sys.exit(e.returncode)